import React, { useState } from 'react';
import { parseCV } from '../services/api';

function CVUpload({ onSkillsExtracted }) {
  const [file, setFile] = useState(null);
  const [skills, setSkills] = useState([]);
  const [manualInput, setManualInput] = useState('');
  const [isParsing, setIsParsing] = useState(false);
  const [error, setError] = useState(null);
  const [activeTab, setActiveTab] = useState('upload'); // 'upload' or 'manual'

  const handleFileChange = (e) => {
    setFile(e.target.files[0]);
    setError(null);
  };

  const handleManualSubmit = async () => {
    if (!manualInput.trim()) return;

    setIsParsing(true);
    setError(null);

    try {
      const extractedSkills = await parseCV(manualInput);
      setSkills(extractedSkills);
      onSkillsExtracted(extractedSkills);
    } catch (err) {
      setError('Failed to parse skills from manual input');
      console.error(err);
    } finally {
      setIsParsing(false);
    }
  };

  const handleFileSubmit = async () => {
    if (!file) return;

    setIsParsing(true);
    setError(null);

    try {
      // Simulate file parsing (replace with actual parsing)
      setTimeout(() => {
        const extractedSkills = ['JavaScript', 'React', 'Node.js', 'CSS', 'HTML'];
        setSkills(extractedSkills);
        onSkillsExtracted(extractedSkills);
        setIsParsing(false);
      }, 2000);
    } catch (err) {
      setError('Failed to parse CV file');
      console.error(err);
      setIsParsing(false);
    }
  };

  return (
    <div className="card">
      <h2 className="text-xl font-semibold mb-4">Upload Your CV</h2>

      <div className="flex border-b border-gray-200 mb-4">
        <button
          className={`px-4 py-2 font-medium ${activeTab === 'upload' ? 'text-primary border-b-2 border-primary' : 'text-gray-500'}`}
          onClick={() => setActiveTab('upload')}
        >
          Upload CV
        </button>
        <button
          className={`px-4 py-2 font-medium ${activeTab === 'manual' ? 'text-primary border-b-2 border-primary' : 'text-gray-500'}`}
          onClick={() => setActiveTab('manual')}
        >
          Manual Input
        </button>
      </div>

      {activeTab === 'upload' ? (
        <div className="space-y-4">
          <div className="border-2 border-dashed border-gray-300 rounded-lg p-8 text-center">
            <div className="flex flex-col items-center justify-center">
              <svg className="w-12 h-12 text-gray-400 mb-2" fill="none" stroke="currentColor" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12"></path>
              </svg>
              <p className="text-gray-600 mb-2">Drag & drop your CV here</p>
              <p className="text-gray-500 text-sm mb-4">PDF format only, max 5MB</p>
              <label className="btn-secondary cursor-pointer">
                Browse Files
                <input 
                  type="file" 
                  accept=".pdf" 
                  onChange={handleFileChange} 
                  className="hidden"
                />
              </label>
            </div>
          </div>

          {file && (
            <div className="flex items-center justify-between bg-gray-50 p-3 rounded-lg">
              <div className="flex items-center">
                <svg className="w-8 h-8 text-red-500 mr-3" fill="none" stroke="currentColor" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z"></path>
                </svg>
                <div>
                  <p className="font-medium">{file.name}</p>
                  <p className="text-sm text-gray-500">{(file.size / 1024 / 1024).toFixed(2)} MB</p>
                </div>
              </div>
              <button 
                onClick={() => setFile(null)}
                className="text-gray-400 hover:text-gray-600"
              >
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12"></path>
                </svg>
              </button>
            </div>
          )}

          <button 
            onClick={handleFileSubmit} 
            className="btn-primary w-full"
            disabled={isParsing || !file}
          >
            {isParsing ? (
              <span className="flex items-center justify-center">
                <svg className="animate-spin -ml-1 mr-2 h-4 w-4 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                  <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                  <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                </svg>
                Parsing CV...
              </span>
            ) : 'Parse CV'}
          </button>
        </div>
      ) : (
        <div className="space-y-4">
          <textarea 
            value={manualInput} 
            onChange={(e) => setManualInput(e.target.value)} 
            placeholder="Paste your CV text or list your skills here..."
            className="input-field h-32"
          />
          <button 
            onClick={handleManualSubmit} 
            className="btn-primary w-full"
            disabled={isParsing || !manualInput.trim()}
          >
            {isParsing ? 'Parsing...' : 'Submit Skills'}
          </button>
        </div>
      )}

      {error && (
        <div className="mt-4 p-3 bg-red-50 text-red-700 rounded-lg flex items-start">
          <svg className="w-5 h-5 mr-2 mt-0.5 flex-shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z"></path>
          </svg>
          <span>{error}</span>
        </div>
      )}

      {skills.length > 0 && (
        <div className="mt-6">
          <h3 className="font-medium text-gray-700 mb-2">Extracted Skills:</h3>
          <div className="flex flex-wrap gap-2">
            {skills.map((skill, i) => (
              <span key={i} className="px-3 py-1 bg-indigo-100 text-indigo-800 rounded-full text-sm">
                {skill}
              </span>
            ))}
          </div>
        </div>
      )}
    </div>
  );
}

export default CVUpload;
